/**
 * Generate Cal.com firewall config.
 *
 * Data source: https://cal.com/docs/api-reference/v2/introduction
 *
 * Cal.com is a scheduling and calendar platform.
 * Uses Bearer token authentication.
 * Token format: prefixed with "cal_live_".
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://cal.com/docs/api-reference/v2/introduction";
// Token prefix: cal_live_
const PLACEHOLDER_VALUE = "cal_live_CoffeeSafeLocalCoffeeSafeLocalCof00a";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Cal.com API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:cal-com",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const calComFirewall = {",
    '  name: "cal-com",',
    '  description: "Cal.com API",',
    "  placeholders: {",
    `    CALCOM_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.cal.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.CALCOM_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Cal.com firewall config...");
  const ts = generateTypeScript();
  writeOutput("cal-com", ts, import.meta.dirname);
}
